/**
 * Extended-playbook manifest guard (spec-v6 full-catalog wiring).
 *
 * `playbooks/extended.json` is the served bundle of every v3 + v4 playbook —
 * the live pipeline fetches it so the matcher can route to those families and
 * their rules can fire. It is generated by `tools/build-extended-playbooks.ts`
 * from `src/playbooks/{v3,v4}/`. This test (a) fails on drift between the
 * committed manifest and a fresh regeneration, and (b) asserts every entry
 * validates against the public `PlaybookSchema` and matches a known rule-set
 * playbook id, so the served catalog can never silently fall out of sync.
 */

import { describe, expect, it } from "vitest";
import { readFileSync } from "node:fs";
import {
  collectExtendedPlaybooks,
  renderManifest,
  EXTENDED_MANIFEST_PATH,
} from "../../tools/build-extended-playbooks.js";
import { parsePlaybook, LAUNCH_PLAYBOOK_IDS } from "../../src/playbooks/index.js";
import { V3_RULES, V4_RULES } from "../../src/engine/index.js";

describe("extended playbook manifest", () => {
  it("the committed manifest matches a fresh regeneration (no drift)", () => {
    const committed = readFileSync(EXTENDED_MANIFEST_PATH, "utf8");
    const regenerated = renderManifest(collectExtendedPlaybooks());
    expect(
      committed,
      "playbooks/extended.json is stale — run `npm run playbooks:bundle` and commit",
    ).toBe(regenerated);
  });

  it("every manifest entry validates against PlaybookSchema", () => {
    const raw = JSON.parse(readFileSync(EXTENDED_MANIFEST_PATH, "utf8")) as unknown[];
    expect(raw.length).toBeGreaterThan(100);
    for (const entry of raw) {
      // Throws on a schema violation, naming the offending playbook.
      expect(() => parsePlaybook(entry)).not.toThrow();
    }
  });

  it("ids are unique and every v3/v4 rule has at least one servable gate-target playbook", () => {
    const raw = JSON.parse(readFileSync(EXTENDED_MANIFEST_PATH, "utf8")) as Array<{ id: string }>;
    const ids = new Set(raw.map((p) => p.id));
    expect(ids.size, "duplicate playbook ids in manifest").toBe(raw.length);

    // The invariant this wiring guarantees: every v3/v4 rule can actually
    // fire in the live pipeline — i.e. at least one of its applies_to_playbooks
    // is servable (in the extended manifest or the launch set). A rule may
    // also list aspirational ids (e.g. "baa-deep") that have no playbook; that
    // is harmless as long as one real target exists.
    const servable = new Set([...ids, ...LAUNCH_PLAYBOOK_IDS]);
    const unfireable: string[] = [];
    for (const r of [...V3_RULES, ...V4_RULES]) {
      const targets = r.applies_to_playbooks ?? [];
      if (targets.length > 0 && !targets.some((id) => servable.has(id))) {
        unfireable.push(r.id);
      }
    }
    expect(
      unfireable.sort(),
      `rules whose gate targets are all unservable (can never fire): ${unfireable.join(", ")}`,
    ).toEqual([]);
  });
});
